/*
  Nemunas Travel / River Cruise Operator
  Global layout, header, and footer styles
*/

:root {
  --color-primary-light: #7FAFD9;
  --color-primary: #3B88E2;
  --color-secondary-light: #EAF3FB;
  --color-secondary-dark: #1F3F60;
  --color-accent: #3B88E2;
  --color-neutral-0: #FFFFFF;
  --color-neutral-50: #F5F7FA;
  --color-neutral-900: #222222;
  --color-border-subtle: #E0E4EA;

  --color-success: #2E7D32;
  --color-error: #C62828;
  --color-warning: #ED6C02;
  --color-info: #0288D1;

  --font-heading: "Libre Franklin", Helvetica, Arial, sans-serif;
  --font-body: "Work Sans", Arial, sans-serif;

  --font-size-h1: 36px;
  --font-size-h2: 28px;
  --font-size-h3: 22px;
  --font-size-body: 16px;
  --font-size-small: 13px;

  --line-height-tight: 1.2;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.75;

  --space-xxs: 4px;
  --space-xs: 8px;
  --space-sm: 16px;
  --space-md: 24px;
  --space-lg: 32px;
  --space-xl: 48px;
  --space-xxl: 64px;

  --radius-sm: 3px;
  --radius-md: 4px;

  --shadow-subtle: 0 1px 3px rgba(0, 0, 0, 0.06);
}

*,
*::before,
*::after {
  box-sizing: border-box;
}

html {
  font-size: 100%;
}

body {
  margin: 0;
  padding: 0;
  font-family: var(--font-body);
  font-size: var(--font-size-body);
  line-height: var(--line-height-relaxed);
  color: var(--color-neutral-900);
  background-color: var(--color-neutral-0);
}

.container {
  max-width: 960px;
  margin: 0 auto;
  padding: 0 var(--space-sm);
}

a {
  color: var(--color-accent);
  text-decoration: none;
}

a:hover,
a:focus {
  text-decoration: underline;
}

.visually-hidden {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  white-space: nowrap;
  border: 0;
}

h1, h2, h3, h4, h5, h6 {
  font-family: var(--font-heading);
  font-weight: 300;
  text-transform: uppercase;
  letter-spacing: 0.16em;
  margin: 0 0 var(--space-md);
  line-height: var(--line-height-tight);
}

h1 {
  font-size: var(--font-size-h1);
  text-align: center;
}

h2 {
  font-size: var(--font-size-h2);
}

h3 {
  font-size: var(--font-size-h3);
}

p {
  margin: 0 0 var(--space-sm);
}

/* Header */

.site-header {
  padding: var(--space-md) 0 var(--space-sm);
}

.header-inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--space-md);
}

.brand {
  display: inline-flex;
  align-items: center;
  gap: var(--space-sm);
  text-decoration: none;
}

.brand-mark {
  width: 56px;
  height: 56px;
  background: var(--color-primary-light);
  border-radius: 8px;
  position: relative;
  box-shadow: var(--shadow-subtle);
}

.brand-mark::before,
.brand-mark::after {
  content: "";
  position: absolute;
  left: 10%;
  right: 10%;
  height: 6px;
  border-radius: 999px;
  background: rgba(255, 255, 255, 0.85);
}

.brand-mark::before {
  top: 18px;
}

.brand-mark::after {
  bottom: 18px;
}

.brand-text {
  display: flex;
  flex-direction: column;
  line-height: 1.1;
}

.brand-name {
  font-family: var(--font-heading);
  font-weight: 300;
  letter-spacing: 0.24em;
  text-transform: uppercase;
  color: var(--color-primary-light);
  font-size: 20px;
}

.brand-subtitle {
  font-family: var(--font-heading);
  font-weight: 300;
  letter-spacing: 0.36em;
  text-transform: uppercase;
  color: #B0BCCB;
  font-size: 12px;
}

.site-nav {
  flex: 1 1 auto;
}

.nav-list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  justify-content: center;
  gap: var(--space-lg);
}

.nav-item {
  position: relative;
}

.nav-link {
  font-family: var(--font-heading);
  font-size: var(--font-size-small);
  letter-spacing: 0.18em;
  text-transform: uppercase;
  color: var(--color-neutral-900);
  text-decoration: none;
  padding-bottom: 2px;
}

.nav-link:hover,
.nav-link:focus {
  color: var(--color-primary);
  text-decoration: none;
}

.nav-link.is-active {
  color: var(--color-primary);
}

.header-utilities {
  display: flex;
  align-items: center;
  gap: var(--space-sm);
  white-space: nowrap;
}

.header-phone {
  font-family: var(--font-heading);
  font-size: var(--font-size-small);
  color: var(--color-primary);
  letter-spacing: 0.08em;
}

.header-faq {
  font-family: var(--font-heading);
  font-size: var(--font-size-small);
  color: var(--color-neutral-900);
  letter-spacing: 0.12em;
  text-transform: uppercase;
}

.header-faq:hover,
.header-faq:focus {
  color: var(--color-primary);
}

.header-languages {
  display: flex;
  align-items: center;
  gap: 4px;
}

.language-flag {
  width: 20px;
  height: 14px;
  border-radius: 1px;
  border: 1px solid var(--color-border-subtle);
  padding: 0;
  background-size: cover;
  background-repeat: no-repeat;
  background-position: center;
  cursor: default;
}

.flag-lt {
  background: linear-gradient(to bottom, #FDB913 0 33%, #006A44 33% 66%, #C1272D 66% 100%);
}

.flag-en {
  background: linear-gradient(to bottom, #FFFFFF 0 50%, #CF142B 50% 100%);
}

.site-content {
  padding-top: var(--space-xl);
  padding-bottom: var(--space-xl);
}

/* Footer */

.site-footer {
  border-top: 1px solid var(--color-border-subtle);
  background-color: var(--color-neutral-0);
  padding: var(--space-lg) 0 var(--space-md);
  font-size: var(--font-size-small);
}

.footer-top {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: var(--space-lg);
  margin-bottom: var(--space-md);
}

.footer-brand {
  display: flex;
  align-items: center;
  gap: var(--space-sm);
}

.footer-brand-text {
  display: flex;
  flex-direction: column;
}

.footer-brand-name {
  font-family: var(--font-heading);
  font-size: 14px;
  letter-spacing: 0.16em;
  text-transform: uppercase;
  color: var(--color-secondary-dark);
}

.footer-brand-tagline {
  font-family: var(--font-body);
  font-size: 12px;
  color: #6F7785;
}

.footer-nav {
  flex: 1 1 auto;
}

.footer-links {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-wrap: wrap;
  justify-content: flex-end;
  gap: var(--space-sm) var(--space-md);
}

.footer-link {
  color: #6F7785;
  text-decoration: none;
  text-transform: uppercase;
  letter-spacing: 0.12em;
}

.footer-link:hover,
.footer-link:focus {
  color: var(--color-primary);
  text-decoration: none;
}

.footer-bottom {
  border-top: 1px solid var(--color-border-subtle);
  padding-top: var(--space-sm);
  text-align: center;
  color: #9AA2B1;
}

/* Responsive tweaks */

@media (max-width: 960px) {
  .header-inner {
    flex-wrap: wrap;
    justify-content: center;
  }

  .site-nav {
    order: 3;
    width: 100%;
    margin-top: var(--space-sm);
  }

  .nav-list {
    flex-wrap: wrap;
    gap: var(--space-sm);
  }

  .header-utilities {
    order: 2;
  }

  .footer-top {
    flex-direction: column;
    align-items: flex-start;
  }

  .footer-links {
    justify-content: flex-start;
  }
}
